import React, { useState, useRef } from 'react';

const InputForm = ({ onGenerate, isLoading, llmConfig }) => {
  const [inputType, setInputType] = useState('manual');
  const [word, setWord] = useState('よろしくお願いします');
  const [scenario, setScenario] = useState('work conversations in a IT engineering company');
  const [cefrLevel, setCefrLevel] = useState('B1');
  const [fileWords, setFileWords] = useState([]);
  const [fileName, setFileName] = useState('');
  const fileInputRef = useRef(null);

  const cefrLevels = [
    { value: 'A1', label: 'A1 - Beginner' },
    { value: 'A2', label: 'A2 - Elementary' },
    { value: 'B1', label: 'B1 - Intermediate' },
    { value: 'B2', label: 'B2 - Upper Intermediate' },
    { value: 'C1', label: 'C1 - Advanced' },
    { value: 'C2', label: 'C2 - Mastery' },
  ];

  const parseWords = (text) => {
    if (!text) return [];
    return text
      .split(/[\n,]+/) // Split by one or more newlines or commas
      .map(w => w.trim())
      .filter(Boolean); // Remove any empty strings
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const wordsToGenerate = inputType === 'manual' ? parseWords(word) : fileWords;
    if (wordsToGenerate.length > 0 && scenario.trim() && !isLoading) {
      onGenerate(wordsToGenerate, scenario, cefrLevel);
    }
  };

  const handleFileChange = (event) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result;
      const words = parseWords(text as string);
      setFileWords(words);
    };
    reader.readAsText(file);
  };

  const clearFile = () => {
    setFileWords([]);
    setFileName('');
    if(fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  }

  const isSubmitDisabled = 
    isLoading ||
    (inputType === 'file' && fileWords.length === 0) ||
    (inputType === 'manual' && !word.trim()) ||
    (llmConfig.service === 'ollama' && !llmConfig.ollamaModel);


  const tabStyle = "px-4 py-2 text-sm font-medium rounded-t-lg transition-colors focus:outline-none";
  const activeTabStyle = "bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 border-l border-t border-r -mb-px text-primary";
  const inactiveTabStyle = "bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700";

  return (
    <div className="bg-white dark:bg-slate-800 p-8 rounded-lg shadow-lg w-full max-w-2xl mx-auto">
        <div className="flex border-b border-slate-200 dark:border-slate-700">
            <button onClick={() => setInputType('manual')} className={`${tabStyle} ${inputType === 'manual' ? activeTabStyle : inactiveTabStyle}`}>Manual Entry</button>
            <button onClick={() => setInputType('file')} className={`${tabStyle} ${inputType === 'file' ? activeTabStyle : inactiveTabStyle}`}>File Upload</button>
        </div>
      <form onSubmit={handleSubmit} className="space-y-6 pt-6">
        {inputType === 'manual' && (
             <div>
                <label htmlFor="word" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                    Japanese Words or Phrases
                </label>
                <textarea
                    id="word"
                    rows={5}
                    value={word}
                    onChange={(e) => setWord(e.target.value)}
                    placeholder="Enter words separated by commas or new lines, e.g.,&#10;お疲れ様です,&#10;すみません"
                    className="w-full px-4 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-primary focus:border-primary font-jp text-lg bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white dark:placeholder-slate-400"
                    required
                />
            </div>
        )}

        {inputType === 'file' && (
            <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                    Word List File (.txt)
                </label>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".txt,text/plain" className="hidden"/>
                <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full text-left px-4 py-2 border border-dashed border-slate-300 dark:border-slate-600 rounded-md text-slate-500 dark:text-slate-400 hover:border-primary hover:text-primary">
                    {fileName || "Choose a .txt file with words separated by lines or commas..."}
                </button>
                {fileWords.length > 0 && (
                    <div className="mt-4 p-3 bg-slate-50 dark:bg-slate-700/50 rounded-md max-h-32 overflow-y-auto">
                        <div className="flex justify-between items-center mb-2">
                            <h4 className="font-semibold text-slate-700 dark:text-slate-300 text-sm">Loaded Words ({fileWords.length})</h4>
                            <button type="button" onClick={clearFile} className="text-xs text-red-500 hover:underline">Clear</button>
                        </div>
                        <ul className="text-sm text-slate-600 dark:text-slate-400 list-disc list-inside">
                            {fileWords.map((fw, i) => <li key={i}>{fw}</li>)}
                        </ul>
                    </div>
                )}
            </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="md:col-span-3">
            <label htmlFor="scenario" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
              Scenario / Context
            </label>
            <input
              type="text"
              id="scenario"
              value={scenario}
              onChange={(e) => setScenario(e.target.value)}
              placeholder="e.g., Leaving the office for the day"
              className="w-full px-4 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-primary focus:border-primary text-lg bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white dark:placeholder-slate-400"
              required
            />
          </div>
          <div className="md:col-span-1">
            <label htmlFor="cefr" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
              CEFR Level
            </label>
            <select
              id="cefr"
              value={cefrLevel}
              onChange={(e) => setCefrLevel(e.target.value)}
              className="w-full px-4 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-primary focus:border-primary text-lg bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white"
            >
              {cefrLevels.map(lvl => (
                <option key={lvl.value} value={lvl.value}>{lvl.label}</option>
              ))}
            </select>
          </div>
        </div>
        <div>
          <button
            type="submit"
            disabled={isSubmitDisabled}
            className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-lg font-medium text-white bg-primary hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary disabled:bg-slate-400 dark:disabled:bg-slate-600 disabled:cursor-not-allowed transition-colors"
          >
            {isLoading ? 'Generating...' : 'Generate Examples'}
          </button>
          {!isLoading && (llmConfig.service === 'ollama' && !llmConfig.ollamaModel) && (
            <p className="text-xs text-center text-amber-700 dark:text-amber-500 mt-2">Please select an Ollama model in Settings before generating.</p>
          )}
        </div>
      </form>
    </div>
  );
};

export default InputForm;

import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import LoadingSpinner from './components/LoadingSpinner';
import ReviewPage from './components/ReviewPage';
import SettingsSidebar from './components/SettingsSidebar';

import { generateWithGemini } from './services/llm/gemini';
import { generateWithOllama } from './services/llm/ollama';

const themeColors: Record<string, { primary: string; secondary: string; light: string; background: string }> = {
  sky: { primary: '#38bdf8', secondary: '#2c3e50', light: '#e0f2fe', background: '#f0fdf4' }, // Sky 400
  emerald: { primary: '#34d399', secondary: '#064e3b', light: '#d1fae5', background: '#ecfdf5' }, // Emerald 400
  violet: { primary: '#a78bfa', secondary: '#4c1d95', light: '#ede9fe', background: '#f5f3ff' }, // Violet 400
  rose: { primary: '#fb7185', secondary: '#881337', light: '#ffe4e6', background: '#fff1f2' }, // Rose 400
  amber: { primary: '#fbbf24', secondary: '#78350f', light: '#fef3c7', background: '#fffbeb' }, // Amber 400
  indigo: { primary: '#818cf8', secondary: '#312e81', light: '#e0e7ff', background: '#eef2ff' }, // Indigo 400
  midnight: { primary: '#8b5cf6', secondary: '#0f172a', light: '#ddd6fe', background: '#f8fafc' }, // Violet 500, Slate 900
};

const App = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<any[] | null>(null);
  const [currentPage, setCurrentPage] = useState('generator');

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState({
    service: 'gemini',
    geminiModel: 'gemini-3-flash-preview',
    ollamaModel: '',
    ollamaUrl: 'http://localhost:11434',
    theme: 'light',
    colorTheme: 'sky',
  });

  const [showRomaji, setShowRomaji] = useState(true);
  const [showEnglish, setShowEnglish] = useState(true);
  const isCancelledRef = useRef(false);

  useEffect(() => {
    try {
        const savedSettings = localStorage.getItem('kaiwa-renshuu-settings');
        if (savedSettings) {
            const parsedSettings = JSON.parse(savedSettings);
            const { geminiApiKey, ...rest } = parsedSettings;
            setSettings(prev => ({...prev, ...rest}));
        }
    } catch (e) {
        console.error("Failed to parse settings from localStorage", e);
    }
  }, []);

  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  // Apply color theme
  useEffect(() => {
    const colors = themeColors[settings.colorTheme] || themeColors.sky;
    const root = document.documentElement;
    root.style.setProperty('--color-primary', colors.primary);
    root.style.setProperty('--color-secondary', colors.secondary);
    root.style.setProperty('--color-light', colors.light);
    root.style.setProperty('--color-background', colors.background);
  }, [settings.colorTheme]);

  const handleSaveSettings = (newSettings: any) => {
    const { geminiApiKey, ...safeSettings } = newSettings;
    setSettings(safeSettings);
    try {
        localStorage.setItem('kaiwa-renshuu-settings', JSON.stringify(safeSettings));
    } catch (e) {
        console.error("Failed to save settings to localStorage", e);
    }
    setIsSettingsOpen(false);
  };

  const handleStop = () => {
    isCancelledRef.current = true;
    setLoadingMessage("Stopping generation...");
  };

  const handleDeleteResult = (indexToDelete: number) => {
    setResults(prevResults => (prevResults || []).filter((_, index) => index !== indexToDelete));
  };

  const handleExportAll = () => {
    if (!results || results.length === 0) return;

    const slugify = (text: string) => {
      return text
        .toLowerCase()
        .trim()
        .replace(/[^ \p{L}\p{N}]+/gu, '')
        .replace(/\s+/g, '-')
        .slice(0, 50);
    };

    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const datePrefix = `${year}${month}${day}`;

    const firstWordSlug = slugify(results[0].wordDetails.romaji || 'session');
    const fileName = `${datePrefix}-kaiwa-renshuu-session-${firstWordSlug}.json`;

    const jsonString = JSON.stringify(results, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleGenerate = async (words: string[], scenario: string, cefrLevel: string) => {
    if (settings.service === 'ollama' && (!settings.ollamaUrl || !settings.ollamaModel)) {
      setError("Ollama is selected, but the server URL is missing or no model is selected. Please configure it in Settings.");
      return;
    }

    isCancelledRef.current = false;
    setIsLoading(true);
    setError(null);
    setResults([]);

    for (let i = 0; i < words.length; i++) {
      if (isCancelledRef.current) {
        setError(prevError => (prevError ? `${prevError}\n` : '') + 'Generation stopped by user.');
        break;
      }

      const word = words[i];
      try {
        setLoadingMessage(words.length > 1 ? `Generating ${i + 1} of ${words.length}: "${word}"` : `Generating content for "${word}"...`);

        let generatedResult;
        if (settings.service === 'gemini') {
            generatedResult = await generateWithGemini(settings.geminiModel, word, scenario, cefrLevel);
        } else {
            generatedResult = await generateWithOllama(settings.ollamaModel, word, scenario, settings.ollamaUrl, cefrLevel);
        }

        setResults(prevResults => [...(prevResults || []), generatedResult]);
      } catch (err) {
        const errorMessage = err instanceof Error ? err.message : 'An unexpected error occurred.';
        setError(prevError => 
            (prevError ? `${prevError}\n` : '') + `Failed on "${word}": ${errorMessage}`
        );
      }
    }

    setIsLoading(false);
    setLoadingMessage(null);
  };

  const visibilityButtonStyle = "py-2 px-4 rounded-md border shadow-sm text-sm font-medium focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors";
  const activeVisibilityStyle = "bg-primary text-white border-primary";
  const inactiveVisibilityStyle = "bg-white dark:bg-slate-700 text-slate-700 dark:text-slate-200 border-slate-300 dark:border-slate-600 hover:bg-slate-50 dark:hover:bg-slate-600";

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header currentPage={currentPage} setCurrentPage={setCurrentPage} onOpenSettings={() => setIsSettingsOpen(true)} />
      <SettingsSidebar 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveSettings}
        currentSettings={settings}
      />
      <main className="flex-grow container mx-auto p-4 md:p-8">
        {currentPage === 'generator' && (
          <>
            <InputForm onGenerate={handleGenerate} isLoading={isLoading} llmConfig={settings} />

            {isLoading && (
              <div className="text-center mt-8">
                <LoadingSpinner message={loadingMessage} />
                <button
                    onClick={handleStop}
                    className="mt-4 py-2 px-6 bg-red-600 text-white font-semibold rounded-lg shadow-md hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-red-500 focus:ring-opacity-75 transition-colors"
                >
                    Stop Generation
                </button>
              </div>
            )}

            {error && (
              <div className="mt-8 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded-lg relative max-w-2xl mx-auto dark:bg-red-900/50 dark:border-red-500/80 dark:text-red-400" role="alert">
                <strong className="font-bold">Error: </strong>
                <span className="block sm:inline whitespace-pre-wrap">{error}</span>
              </div>
            )}

            {results && results.length > 0 && (
              <div className="max-w-4xl mx-auto mt-8 flex justify-between items-center">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-medium text-slate-600 dark:text-slate-300">Show:</span>
                    <button
                      onClick={() => setShowRomaji(prev => !prev)}
                      className={`${visibilityButtonStyle} ${showRomaji ? activeVisibilityStyle : inactiveVisibilityStyle}`}
                      aria-pressed={showRomaji}
                    >
                      Romaji
                    </button>
                    <button
                      onClick={() => setShowEnglish(prev => !prev)}
                      className={`${visibilityButtonStyle} ${showEnglish ? activeVisibilityStyle : inactiveVisibilityStyle}`}
                      aria-pressed={showEnglish}
                    >
                      English
                    </button>
                  </div>
                  <button
                    onClick={handleExportAll}
                    className="bg-secondary dark:bg-primary text-white py-2 px-4 rounded-md hover:bg-slate-700 dark:hover:bg-sky-600 transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-secondary dark:focus:ring-primary inline-flex items-center gap-2 shadow-md"
                    aria-label="Export All Results to JSON"
                    title="Export All Results to JSON"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Export All Results
                  </button>
              </div>
            )}
            {results && results.length > 0 && results.map((result, index) => (
              <ResultDisplay 
                key={index} 
                result={result} 
                showRomaji={showRomaji} 
                showEnglish={showEnglish} 
                onDelete={handleDeleteResult}
                index={index}
              />
            ))}
          </>
        )}
        {currentPage === 'review' && <ReviewPage />}
      </main>
      <Footer />
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    wordDetails: {
      type: Type.OBJECT,
      description: "The different writings of the word.",
      properties: {
        kanji: {
          type: Type.STRING,
          description: "The word in its original form, possibly including kanji (e.g., '日本語').",
        },
        kana: {
          type: Type.STRING,
          description: "The hiragana or katakana reading of the word (e.g., 'にほんご').",
        },
        romaji: {
          type: Type.STRING,
          description: "The romaji transliteration of the word (e.g., 'nihongo').",
        },
      },
      required: ["kanji", "kana", "romaji"]
    },
    meaning: {
      type: Type.STRING,
      description: "The detailed English meaning of the Japanese word/phrase, contextualized for the given scenario.",
    },
    conversations: {
      type: Type.ARRAY,
      description: "An array of 5 distinct example conversations.",
      items: {
        type: Type.OBJECT,
        properties: {
          title: {
            type: Type.STRING,
            description: "A short, descriptive title for the conversation."
          },
          dialogue: {
            type: Type.ARRAY,
            description: "The lines of dialogue in the conversation.",
            items: {
              type: Type.OBJECT,
              properties: {
                speaker: { type: Type.STRING, description: "The speaker's name or role (e.g., 'A-san', '店員')." },
                japanese: { type: Type.STRING, description: "The dialogue line in Japanese, with furigana for kanji in the format '漢字[かんじ]'." },
                romaji: { type: Type.STRING, description: "The romaji transliteration of the Japanese line." },
                english: { type: Type.STRING, description: "The English translation of the line." },
              },
              required: ["speaker", "japanese", "romaji", "english"]
            }
          }
        },
        required: ["title", "dialogue"]
      }
    }
  },
  required: ["wordDetails", "meaning", "conversations"]
};


export const generateWithGemini = async (model: string, word: string, scenario: string, cefrLevel: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const prompt = `
    You are an expert Japanese language teacher.
    Your student wants to learn the word/phrase: "${word}".
    The context for learning is the following scenario: "${scenario}".
    The target Japanese proficiency level is CEFR: "${cefrLevel}".

    Your task is to provide the following in a structured JSON format:
    1.  **wordDetails**: An object containing the kanji, kana, and romaji writings of "${word}".
    2.  **meaning**: A clear and concise English definition of "${word}", specifically explaining its nuance and usage within the context of the provided scenario: "${scenario}".
    3.  **conversations**: Exactly 5 distinct, practical, and natural-sounding example conversations that demonstrate how to use "${word}" within the specified scenario: "${scenario}".

    IMPORTANT PROFICIENCY RULES:
    - All conversations, vocabulary selection, and sentence complexity MUST strictly align with the "${cefrLevel}" CEFR level.
    - For lower levels (A1-A2), use simpler grammar and common words.
    - For higher levels (B2-C2), use more nuanced, formal, or specialized language appropriate for the scenario.

    IMPORTANT FORMATTING RULES:
    - For each 'japanese' dialogue line, provide furigana for all kanji using the format 'BaseKanji[reading]'.
    - For example, '日本語が話せます' should be formatted as '日[に]本[ほん]語[ご]が話[はな]せます'.
    - Kana-only words should not have brackets.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model || "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const jsonText = response.text || "";
    const parsedResult = JSON.parse(jsonText.trim());

    if (!parsedResult.wordDetails || !parsedResult.meaning || !Array.isArray(parsedResult.conversations)) {
        throw new Error("Invalid response structure from API.");
    }

    return parsedResult;

  } catch (error) {
    console.error("Error generating content from Gemini API:", error);
    if (error instanceof Error) {
        throw new Error(`Failed to generate learning content: ${error.message}`);
    }
    throw new Error("An unknown error occurred while communicating with the AI.");
  }
};

export const fetchOllamaModels = async (url) => {
    const response = await fetch(new URL('/api/tags', url));
    if (!response.ok) {
        throw new Error(`Failed to fetch models from Ollama. Status: ${response.status}`);
    }
    const data = await response.json();
    return data.models.map(model => model.name);
};


export const generateWithOllama = async (
    model, 
    word, 
    scenario, 
    url,
    cefrLevel
) => {
    const prompt = `
    You are an expert Japanese language teacher.
    Your student wants to learn the word/phrase: "${word}".
    The context for learning is the following scenario: "${scenario}".
    The target Japanese proficiency level is CEFR: "${cefrLevel}".

    Your task is to provide a JSON object that follows a specific structure.
    Respond with ONLY the raw JSON object, without any surrounding text, explanations, or markdown formatting like \`\`\`json.

    The JSON object must contain these exact keys: "wordDetails", "meaning", and "conversations".
    1.  "wordDetails": An object containing the "kanji" (original form), "kana" (reading), and "romaji" writings of "${word}".
    2.  "meaning": A clear and concise English definition of "${word}", specifically explaining its nuance and usage within the context of the provided scenario: "${scenario}".
    3.  "conversations": An array of EXACTLY 5 distinct, practical, and natural-sounding example conversations using "${word}" in the context of "${scenario}".
        - Each object in the "conversations" array must have a "title" and a "dialogue" array.
        - Each object in the "dialogue" array must have "speaker", "japanese", "romaji", and "english" keys.

    PROFICIENCY RULES:
    - All Japanese dialogue MUST align with the "${cefrLevel}" CEFR proficiency level.
    - Adjust vocabulary and grammar complexity to match "${cefrLevel}".

    FORMATTING RULE: For each "japanese" dialogue line, you MUST provide furigana for all kanji using the format 'BaseKanji[reading]'.
    For example, '日本語が話せます' should be formatted as '日[に]本[ほん]語[ご]が話[はな]せます'.
    Kana-only words or particles should not have brackets.
    `;

    try {
        const response = await fetch(new URL('/api/generate', url), {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                model,
                prompt,
                stream: false,
                format: 'json',
            }),
        });

        if (!response.ok) {
            throw new Error(`Ollama API request failed with status ${response.status}`);
        }

        const result = await response.json();
        const parsedResult = JSON.parse(result.response);

        if (!parsedResult.wordDetails || !parsedResult.meaning || !Array.isArray(parsedResult.conversations)) {
            throw new Error("Invalid response structure from Ollama model.");
        }

        return parsedResult;

    } catch (error) {
        console.error("Error generating content from Ollama API:", error);
        if (error instanceof Error) {
            throw new Error(`Failed to generate learning content with Ollama: ${error.message}`);
        }
        throw new Error("An unknown error occurred while communicating with the Ollama API.");
    }
};
